def main() -> None:
    a: int = 10
    b: int = 3
    print(a + b)
    print(a - b)
    print(a * b)
    print(a / b)
    print(a // b)
    print(a % b)
    print(a ** b)
    print(-a)
    print(abs(-a))
    print(int(3.7))
    print(int("42"))
    print(int("ff", 16))
    print(int("101", 2))


if __name__ == "__main__":
    main()
